<?php require '../config.php'; require_admin(); require '_nav.php'; $rows=$pdo->query('SELECT l.*,u.name user_name FROM activity_logs l LEFT JOIN users u ON u.id=l.user_id ORDER BY l.id DESC LIMIT 200')->fetchAll(); ?>
<!doctype html><html><head><title>Activity Logs</title><link rel="stylesheet" href="/style.css"><meta name="viewport" content="width=device-width,initial-scale=1"></head><body><div class="dash"><?php admin_nav(); ?><div class="main"><h1>Activity Logs</h1><table class="table"><tr><th>Action</th><th>User</th><th>Details</th><th>Date</th></tr><?php foreach($rows as $r):?><tr><td><?=h($r['action'])?></td><td><?=h($r['user_name'] ?: '-')?></td><td><?=h($r['details'])?></td><td><?=h($r['created_at'])?></td></tr><?php endforeach;?></table></div></div></body></html>
